/// <summary>
/// Extracts the menu item reference from a single tile.
/// </summary>
/// <param name="_tile">The tile metadata object to process.</param>
/// <param name="_path">The parent path for building the reference location.</param>
protected void processTile(AxTile _tile, str _path)
